+    #[test]
+    fn init_tracking_sets_up_vectors() {
+        let form = Form::new(vec![
+            FormField::text("Name"),
+            FormField::checkbox("Agree", false),
+            FormField::number("Age", 25),
+        ]);
+        let mut state = FormState::default();
+        state.init_tracking(&form);
+
+        assert_eq!(state.touched.len(), 3);
